import pytest
import requests
import copy

def test_create_medication_request_on_cancelled_encounter_returns_409(
    prescriber_token, base_url, non_controlled_rx_payload, cancelled_encounter_id
):
    payload = copy.deepcopy(non_controlled_rx_payload)
    payload["encounter"] = {
        "reference": f"Encounter/{cancelled_encounter_id}"
    }
    headers = {
        "Authorization": f"Bearer {prescriber_token}",
        "Content-Type": "application/fhir+json"
    }
    resp = requests.post(
        f"{base_url}/MedicationRequest",
        json=payload,
        headers=headers,
        timeout=10
    )
    assert resp.status_code in (409, 422)
    body = resp.json()
    assert body.get("resourceType") == "OperationOutcome"
    issues = body.get("issue", [])
    assert any(
        any(kw in (i.get("diagnostics") or "").lower()
            for kw in ("cancel", "state", "conflict", "invalid"))
        for i in issues
    ), "Expected state-conflict error in OperationOutcome"
